#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int o1, o2;
        scanf("%d %d", &o1, &o2);
        int N = o1 * o2;
        int d[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &d[i]);
        }
        int prefixSum[N + 1] = {0};
        for (int i = 0; i < N; i++) {
            prefixSum[i + 1] = prefixSum[i] + d[i];
        }
        int oneGovernors = 0;
        for (int i = 0; i < o1; i++) {
            int stateSum = prefixSum[i * o2 + o2] - prefixSum[i * o2];
            if (stateSum > o2 / 2) {
                oneGovernors++;
            }
        }
        if (oneGovernors > o1 / 2) {
            printf("1\n");
        } else {
            printf("0\n");
        }
    }
    return 0;
}

